import React, { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import Modal from 'react-modal';

function Courses() {
  const user = useSelector((state) => state.auth.user);
  const [courses, setCourses] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [tests, setTests] = useState([]);
  const [files, setFiles] = useState([]);
  const [studentUploads, setStudentUploads] = useState([]);
  const [uploadFiles, setUploadFiles] = useState({});
  const [modalIsOpen, setModalIsOpen] = useState(false);
  const [modalAction, setModalAction] = useState({ type: '', id: null });
  const [selectedCourse, setSelectedCourse] = useState(null);

  useEffect(() => {
    if (user) {
      if (user.role === "student" && user.id && user.classId) {
        fetchEnrollments();
      } else if (user.role === "teacher" && user.id) {
        fetchTeacherCourses();
      } else if (user.role === "admin" && user.id) {
        fetchAllCourses();
      }
    }
  }, [user]);

  const fetchEnrollments = () => {
    fetch(`http://localhost:3001/enrollments?userId=${user.id}`)
      .then((res) => res.json())
      .then((data) => {
        const enrollmentsArray = Array.isArray(data) ? data : [];
        setEnrollments(enrollmentsArray);
        fetchCourses(`http://localhost:3001/courses?classId=${user.classId}`);
      })
      .catch((error) => {
        console.error("Enrollments fetch error:", error);
        toast.error("Ошибка загрузки записей");
      });
  };

  const fetchTeacherCourses = () => {
    fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
      .then((res) => res.json())
      .then((data) => {
        const coursesArray = Array.isArray(data) ? data : [];
        setCourses(coursesArray);
        fetchFiles(coursesArray.map(c => c.id));
      })
      .catch((error) => {
        console.error("Teacher courses fetch error:", error);
        toast.error("Ошибка загрузки курсов");
      });
  };

  const fetchAllCourses = () => {
    fetch(`http://localhost:3001/courses`)
      .then((res) => res.json())
      .then((data) => {
        const coursesArray = Array.isArray(data) ? data : [];
        setCourses(coursesArray);
        fetchFiles(coursesArray.map(c => c.id));
      })
      .catch((error) => {
        console.error("All courses fetch error:", error);
        toast.error("Ошибка загрузки курсов");
      });
  };

  const fetchCourses = (url) => {
    fetch(url)
      .then((res) => res.json())
      .then((data) => {
        const coursesArray = Array.isArray(data) ? data : [];
        setCourses(coursesArray);
        fetchFiles(coursesArray.map(c => c.id));
        fetchTests(coursesArray.map(c => c.id));
      })
      .catch((error) => {
        console.error("Courses fetch error:", error);
        toast.error("Ошибка загрузки курсов");
      });
  };

  const fetchFiles = (courseIds) => {
    if (courseIds.length > 0) {
      fetch(`http://localhost:3001/files?courseId=${courseIds.join('&courseId=')}`)
        .then((res) => {
          console.log("Files response status:", res.status);
          return res.json();
        })
        .then((data) => {
          console.log("Files data:", data);
          setFiles(Array.isArray(data) ? data : []);
        })
        .catch((error) => {
          console.error("Files fetch error:", error);
          toast.error("Ошибка загрузки файлов");
        });
      if (user.role === "student") {
        fetch(`http://localhost:3001/student_uploads?userId=${user.id}&courseId=${courseIds.join('&courseId=')}`)
          .then((res) => res.json())
          .then((data) => {
            console.log("Student uploads data:", data);
            setStudentUploads(Array.isArray(data) ? data : []);
          })
          .catch((error) => {
            console.error("Student uploads fetch error:", error);
            toast.error("Ошибка загрузки отправленных файлов");
          });
      } else if (user.role === "teacher") {
        fetch(`http://localhost:3001/student_uploads?courseId=${courseIds.join('&courseId=')}`)
          .then((res) => res.json())
          .then((data) => {
            console.log("Student uploads for teacher:", data);
            setStudentUploads(Array.isArray(data) ? data : []);
          })
          .catch((error) => {
            console.error("Student uploads fetch error for teacher:", error);
            toast.error("Ошибка загрузки файлов студентов");
          });
      }
    }
  };

  const fetchTests = (courseIds) => {
    if (courseIds.length > 0) {
      fetch(`http://localhost:3001/tests?courseId=${courseIds.join('&courseId=')}`)
        .then((res) => res.json())
        .then((data) => {
          console.log("Tests data:", data);
          setTests(Array.isArray(data) ? data : []);
        })
        .catch((error) => {
          console.error("Tests fetch error:", error);
          toast.error("Ошибка загрузки тестов");
        });
    } else {
      setTests([]);
    }
  };

  const handleFileChange = (courseId, e) => {
    setUploadFiles((prev) => ({
      ...prev,
      [courseId]: e.target.files[0],
    }));
  };

  const handleFileUpload = async (courseId, e) => {
    e.preventDefault();
    const file = uploadFiles[courseId];
    if (!file) {
      toast.error("Выберите файл для загрузки!");
      return;
    }
    const formData = new FormData();
    formData.append("file", file);
    try {
      const response = await fetch("http://localhost:3002/upload", {
        method: "POST",
        body: formData,
      });
      if (response.ok) {
        const { filename, originalName } = await response.json();
        const uploadData = {
          courseId: parseInt(courseId),
          userId: user.id,
          filename,
          originalName,
          path: `uploads/${filename}`,
          createdAt: new Date().toISOString(),
        };
        const uploadResponse = await fetch("http://localhost:3001/student_uploads", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(uploadData),
        });
        if (uploadResponse.ok) {
          toast.success("Файл успешно загружен!");
          setUploadFiles((prev) => ({ ...prev, [courseId]: null }));
          fetchFiles([courseId]);
          await fetch("http://localhost:3001/notifications", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              userId: user.id,
              message: `Студент загрузил файл "${originalName}" для курса ID ${courseId}.`,
              createdAt: new Date().toISOString(),
            }),
          });
        } else {
          toast.error("Не удалось сохранить данные файла");
        }
      } else {
        toast.error("Не удалось загрузить файл");
      }
    } catch (error) {
      console.error("File upload error:", error);
      toast.error("Сетевая ошибка при загрузке файла");
    }
  };

  const openModal = (type, id, course) => {
    setModalAction({ type, id });
    setSelectedCourse(course);
    setModalIsOpen(true);
  };

  const closeModal = () => {
    setModalIsOpen(false);
    setModalAction({ type: '', id: null });
    setSelectedCourse(null);
  };

  const handleDelete = async () => {
    if (modalAction.type === 'deleteCourse' && modalAction.id) {
      try {
        const response = await fetch(`http://localhost:3001/courses/${modalAction.id}`, {
          method: 'DELETE',
        });
        if (response.ok) {
          toast.success('Курс удален!');
          setCourses(courses.filter(c => c.id !== modalAction.id));
        } else {
          toast.error('Ошибка удаления курса');
        }
      } catch (error) {
        console.error('Delete course error:', error);
        toast.error('Сетевая ошибка при удалении курса');
      }
    }
    closeModal();
  };

  const handleBan = async (userId) => {
    if (modalAction.type === 'banUser' && userId) {
      try {
        const response = await fetch(`http://localhost:3001/users/${userId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ banned: true }),
        });
        if (response.ok) {
          toast.success('Пользователь забанен!');
          // Обновление списка пользователей не требуется, так как это делается в AdminPanel
        } else {
          toast.error('Ошибка бана пользователя');
        }
      } catch (error) {
        console.error('Ban user error:', error);
        toast.error('Сетевая ошибка при бане');
      }
    }
    closeModal();
  };

  if (!user) {
    return <div className="container mt-5"><h1>Пожалуйста, войдите в систему</h1></div>;
  }

  if (user.role === "student" && !user.classId) {
    return <div className="container mt-5"><h1>У вас не указан класс. Обратитесь к администратору.</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Курсы</h1>
      <div className="card shadow">
        <div className="card-body">
          <h2 className="card-title">
            {user.role === "student" ? "Курсы вашего класса" : user.role === "teacher" ? "Ваши преподаваемые курсы" : "Все курсы"}
          </h2>
          {courses.length === 0 ? (
            <p>Нет доступных курсов</p>
          ) : (
            <ul className="list-group">
              {courses.map((course) => (
                <li key={course.id} className="list-group-item">
                  <strong>{course.name}</strong>
                  {(user.role === "student" || user.role === "teacher") && (
                    <div>
                      {user.role === "student" && (
                        <p>
                          Статус: {enrollments.some((e) => e.courseId === course.id) ? "Записан" : "Не записан"}
                          {!enrollments.some((e) => e.courseId === course.id) && (
                            <button
                              className="btn btn-success btn-sm ms-2"
                              onClick={() => {
                                fetch(`http://localhost:3001/enrollments`, {
                                  method: 'POST',
                                  headers: { 'Content-Type': 'application/json' },
                                  body: JSON.stringify({ userId: user.id, courseId: course.id }),
                                })
                                  .then((res) => res.json())
                                  .then(() => {
                                    toast.success('Запись на курс успешна!');
                                    fetchEnrollments();
                                  })
                                  .catch((error) => {
                                    console.error('Enrollment error:', error);
                                    toast.error('Ошибка записи на курс');
                                  });
                              }}
                            >
                              Записаться
                            </button>
                          )}
                        </p>
                      )}
                      <h6>Тесты:</h6>
                      {tests.filter((t) => t.courseId === course.id).length === 0 ? (
                        <p>Тестов нет</p>
                      ) : (
                        <ul>
                          {tests
                            .filter((t) => t.courseId === course.id)
                            .map((test) => (
                              <li key={test.id}>
                                <Link to={`/take-test/${test.id}`}>
                                  {test.title}
                                  {user.role === "student" && !enrollments.some((e) => e.courseId === course.id)
                                    ? " (Требуется запись)"
                                    : ""}
                                </Link>
                              </li>
                            ))}
                        </ul>
                      )}
                      <h6>Файлы от учителя:</h6>
                      {files.filter((f) => f.courseId === course.id).length === 0 ? (
                        <p>Файлов нет</p>
                      ) : (
                        <ul>
                          {files
                            .filter((f) => f.courseId === course.id)
                            .map((file) => (
                              <li key={file.id}>
                                <a
                                  href={`http://localhost:3002/download/${file.filename}`}
                                  download={file.originalName}
                                  rel="noopener noreferrer"
                                >
                                  {file.originalName || file.filename}
                                </a>
                              </li>
                            ))}
                        </ul>
                      )}
                      {user.role === "student" && enrollments.some((e) => e.courseId === course.id) && (
                        <>
                          <h6>Загрузить файл:</h6>
                          <form onSubmit={(e) => handleFileUpload(course.id, e)}>
                            <div className="mb-3">
                              <label htmlFor={`file-${course.id}`} className="form-label">
                                Выберите файл
                              </label>
                              <input
                                type="file"
                                id={`file-${course.id}`}
                                className="form-control"
                                onChange={(e) => handleFileChange(course.id, e)}
                              />
                            </div>
                            <button type="submit" className="btn btn-primary btn-sm">
                              Загрузить
                            </button>
                          </form>
                          <h6>Ваши загруженные файлы:</h6>
                          {studentUploads.filter((u) => u.courseId === course.id).length === 0 ? (
                            <p>Вы еще не загрузили файлы</p>
                          ) : (
                            <ul>
                              {studentUploads
                                .filter((u) => u.courseId === course.id)
                                .map((upload) => (
                                  <li key={upload.id}>
                                    <a
                                      href={`http://localhost:3002/download/${upload.filename}`}
                                      download={upload.originalName}
                                      rel="noopener noreferrer"
                                    >
                                      {upload.originalName || upload.filename}
                                    </a>
                                  </li>
                                ))}
                            </ul>
                          )}
                        </>
                      )}
                      {user.role === "teacher" && (
                        <div>
                          <Link to={`/edit-course/${course.id}`} className="btn btn-secondary btn-sm me-2">
                            Редактировать
                          </Link>
                          <button
                            className="btn btn-danger btn-sm me-2"
                            onClick={() => openModal('deleteCourse', course.id, course)}
                          >
                            Удалить
                          </button>
                        </div>
                      )}
                    </div>
                  )}
                  {user.role === "admin" && (
                    <div>
                      <button
                        className="btn btn-danger btn-sm me-2"
                        onClick={() => openModal('deleteCourse', course.id, course)}
                      >
                        Удалить
                      </button>
                    </div>
                  )}
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
      <Modal
        isOpen={modalIsOpen}
        onRequestClose={closeModal}
        style={{
          content: {
            top: '50%',
            left: '50%',
            right: 'auto',
            bottom: 'auto',
            marginRight: '-50%',
            transform: 'translate(-50%, -50%)',
            width: '300px',
          },
        }}
      >
        <h2>{modalAction.type === 'deleteCourse' ? 'Удаление курса' : 'Бан пользователя'}</h2>
        {modalAction.type === 'deleteCourse' && (
          <p>Вы уверены, что хотите удалить курс "{selectedCourse?.name}"?</p>
        )}
        <button className="btn btn-danger" onClick={handleDelete}>Да</button>
        <button className="btn btn-secondary ms-2" onClick={closeModal}>Нет</button>
      </Modal>
    </div>
  );
}

export default Courses;
